/**
 * Modular exponentiation: (base^exp) % mod
 * Handles BigInts.
 */
function power(base, exp, mod) {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
}

/**
 * Solves the maximum binary number construction problem.
 * @param {number[]} nums1
 * @param {number[]} nums0
 * @returns {number} The maximum resulting integer modulo 10^9 + 7.
 */
function solve(nums1, nums0) {
    const MOD = 1000000007n;

    // 1. Store segment descriptors
    const segments = [];
    for (let i = 0; i < nums1.length; i++) {
        segments.push({
            a1: nums1[i],
            a0: nums0[i]
        });
    }

    // 2. Sort segments based on lexicographical comparison (AB vs BA)
    // A precedes B if AB > BA
    segments.sort((A, B) => {
        const a1 = A.a1, a0 = A.a0;
        const b1 = B.a1, b0 = B.a0;

        // Construct S_A S_B
        const sA_sB = '1'.repeat(a1) + '0'.repeat(a0) + '1'.repeat(b1) + '0'.repeat(b0);

        // Construct S_B S_A
        const sB_sA = '1'.repeat(b1) + '0'.repeat(b0) + '1'.repeat(a1) + '0'.repeat(a0);

        // Lexicographical comparison:
        if (sA_sB > sB_sA) return -1; // A comes before B (we want descending order based on string value)
        if (sA_sB < sB_sA) return 1;  // B comes before A
        return 0;
    });

    // Reversing the sort order to achieve descending lexicographical order (AB > BA => A should come first)
    // Since Array.sort sorts ascendingly, we return -1 if A should come before B.
    segments.sort((A, B) => {
        const a1 = A.a1, a0 = A.a0;
        const b1 = B.a1, b0 = B.a0;

        const sA_sB = '1'.repeat(a1) + '0'.repeat(a0) + '1'.repeat(b1) + '0'.repeat(b0);
        const sB_sA = '1'.repeat(b1) + '0'.repeat(b0) + '1'.repeat(a1) + '0'.repeat(a0);

        if (sA_sB > sB_sA) return -1; // A is "larger" (should come first), return negative
        if (sA_sB < sB_sA) return 1;  // B is "larger", return positive
        return 0;
    });


    // 3 & 4. Calculate the resulting value modulo M
    let totalValue = 0n;
    let currentTotalLength = 0n;

    for (const segment of segments) {
        const a1 = BigInt(segment.a1);
        const a0 = BigInt(segment.a0);
        const L_i = a1 + a0;

        let V_i; // Value of the current segment S_i

        if (a1 === 0n) {
            // Segment is 00...0, value is 0.
            V_i = 0n;
        } else {
            // S_i = 1^a1 0^a0. Value = 2^(a1+a0) - 2^a0 (mod M)
            // Since L_i = a1+a0, this is 2^L_i - 2^a0.

            // 2^L_i mod M
            const term1 = power(2n, L_i, MOD);

            // 2^a0 mod M
            const term2 = power(2n, a0, MOD);

            // V_i = (term1 - term2 + M) mod M
            V_i = (term1 - term2 + MOD) % MOD;
        }

        // Update Total Value: V_new = (V_prev * 2^L_i + V_i) mod M

        // 2^L_i mod M
        const pow2_Li = power(2n, L_i, MOD);

        // V_prev * 2^L_i mod M
        let contribution_shift = (totalValue * pow2_Li) % MOD;

        // V_new mod M
        totalValue = (contribution_shift + V_i) % MOD;

        // Update Total Length
        currentTotalLength += L_i;
    }

    // Return the result as a standard number type, as required by typical contest output formats, 
    // although the calculation required BigInt internally.
    return Number(totalValue);
